// constants
const featureData = [
  {
    title: "Creative Design",
    description:
      "Overcoming all obstacles improves us, develops our ability and makes us stronger.",
  },
  {
    title: "Cool Animations",
    description:
      "Overcoming all obstacles improves us, develops our ability and makes us stronger.",
  },
  {
    title: "Fast & Easy Work",
    description:
      "Overcoming all obstacles improves us, develops our ability and makes us stronger.",
  },
  {
    title: "Quick Result",
    description:
      "Overcoming all obstacles improves us, develops our ability and makes us stronger.",
  },
];

//  ------------------------------ | FEATURE - 6 | ------------------------------  //

export default function Feature6() {
  return (
    <section className="bg-primary pt-20 md:pt-28 pb-0 overflow-hidden text-white">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-6 items-center">
          {/* Left Column: Content */}
          <div className="col-span-12 lg:col-span-7 pb-20 md:pb-28">
            <div className="max-w-2xl">
              <h2 className="mb-6 text-white">Features</h2>
              <p className="text-white/80 mb-14 text-lg lg:text-xl">
                At half-past eight the door opened, the policeman appeared and
                requesting them to follow him, led the way to an adjoining hall.
              </p>

              {/* Nested Grid for Features */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-6">
                {featureData.map((item, index) => (
                  <div key={index} className="flex flex-col gap-3">
                    <h5 className="text-white">{item.title}</h5>
                    <p className="text-white/70">{item.description}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right Column: Mobile Mockup (Cut off at bottom) */}
          <div className="col-span-12 lg:col-span-5 flex justify-center lg:justify-end self-end">
            <div className="relative w-full max-w-[320px] overflow-hidden max-h-96 md:max-h-125">
              <img
                src="https://cdn.uiable.com/block/content-29.png"
                alt="Meetings App Interface"
                className="h-auto w-full object-contain object-top"
              />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
